import sys
from collections import deque

def can_transform(x, y):
    def next_states(num):
        binary = bin(num)[2:]
        results = []
        for bit in ['0', '1']:
            new_binary = (binary + bit)[::-1].lstrip('0')
            if not new_binary:
                new_binary = '0'
            results.append(int(new_binary, 2))
        return results

    visited = set()
    queue = deque([x])
    visited.add(x)

    while queue:
        current = queue.popleft()
        if current == y:
            return True
        # Pruning: if current is much larger than y, no need to continue
        if current > 2 * 10**18:
            continue
        for nxt in next_states(current):
            if nxt == y:
                return True
            if nxt not in visited and nxt <= 2 * 10**18:
                visited.add(nxt)
                queue.append(nxt)

    return False

